     1→import 'server-only';
     2→import { NextRequest, NextResponse } from 'next/server';
     3→import {
     4→  uploadToFileStore,
     5→  updateManifest,
     6→  deleteDocumentsByDisplayName,
     7→  type ManifestFile,
     8→} from '@/../scripts/data-upload/lib/file-uploader';
     9→import path from 'path';
    10→import fs from 'fs';
    11→import type { AdminApiResponse } from '@/types/admin';
    12→
    13→/**
    14→ * Route Segment Config
    15→ * ファイルアップロード用の設定
    16→ */
    17→export const dynamic = 'force-dynamic';
    18→export const maxDuration = 60; // タイムアウトを60秒に設定
    19→
    20→/**
    21→ * Vercel環境かどうかを判定
    22→ */
    23→const isVercel = process.env.VERCEL === '1';
    24→
    25→/**
    26→ * 環境に応じたmanifestファイルパスを取得
    27→ */
    28→function getManifestPath(): string {
    29→  const storeName = process.env.FILE_SEARCH_STORE_NAME || '';
    30→  const isStaging = storeName.includes('staging');
    31→  const fileName = isStaging ? 'file-store-manifest-staging.json' : 'file-store-manifest.json';
    32→  return path.join(process.cwd(), 'data', fileName);
    33→}
    34→
    35→/**
    36→ * manifestのステータスを更新
    37→ * Vercel環境ではファイルシステムへの書き込みができないためスキップ
    38→ */
    39→function updateManifestStatus(
    40→  fileId: string,
    41→  status: 'uploading' | 'completed' | 'failed',
    42→  errorMessage?: string,
    43→  actualFileId?: string
    44→): void {
    45→  // Vercel環境ではファイル書き込み不可
    46→  if (isVercel) {
    47→    console.log(`[Vercel] Manifest update skipped: ${fileId} -> ${status}`);
    48→    return;
    49→  }
    50→
    51→  try {
    52→    const manifestPath = getManifestPath();
    53→    if (!fs.existsSync(manifestPath)) return;
    54→
    55→    const manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
    56→    const fileIndex = manifest.files.findIndex((f: any) => f.file_id === fileId);
    57→
    58→    if (fileIndex !== -1) {
    59→      manifest.files[fileIndex].status = status;
    60→      if (errorMessage) {
    61→        manifest.files[fileIndex].error_message = errorMessage;
    62→      }
    63→      if (actualFileId && status === 'completed') {
    64→        manifest.files[fileIndex].file_id = actualFileId;
    65→      }
    66→      manifest.updated_at = new Date().toISOString();
    67→      fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
    68→    }
    69→  } catch (error) {
    70→    console.error('Manifest update failed:', error);
    71→  }
    72→}
    73→
    74→const MAX_FILE_SIZE = 4.5 * 1024 * 1024; // 4.5MB (Vercelの制限)
    75→
    76→const ALLOWED_EXTENSIONS = ['.txt', '.md', '.json', '.csv', '.xlsx', '.xls', '.pdf'];
    77→
    78→/**
    79→ * バックグラウンドでアップロード処理を実行
    80→ *
    81→ * 重複防止: Store Documents APIで同名ドキュメントを検索・削除してからアップロード
    82→ */
    83→async function processUploadInBackground(
    84→  apiKey: string,
    85→  content: string,
    86→  displayName: string,
    87→  sourceType: 'qa' | 'web',
    88→  locale: string,
    89→  finalCategory: string,
    90→  tempFileId: string
    91→): Promise<void> {
    92→  try {
    93→    console.log(`📤 バックグラウンドアップロード開始: ${displayName}`);
    94→
    95→    // Store Documents APIで同名ドキュメントを検索・削除（重複防止）
    96→    const fileSearchStoreName = process.env.FILE_SEARCH_STORE_NAME;
    97→    if (fileSearchStoreName) {
    98→      console.log(`🔍 同名ドキュメントを検索中: ${displayName}`);
    99→      const deletedCount = await deleteDocumentsByDisplayName(
   100→        apiKey,
   101→        fileSearchStoreName,
   102→        displayName
   103→      );
   104→      if (deletedCount > 0) {
   105→        console.log(`🗑️ 既存ドキュメントを削除しました: ${deletedCount}件`);
   106→      }
   107→    }
   108→
   109→    const uploadResult = await uploadToFileStore(apiKey, content, {
   110→      display_name: displayName,
   111→      source_type: sourceType,
   112→      locale: locale,
   113→      category: finalCategory,
   114→    });
   115→
   116→    if (!uploadResult.success) {
   117→      console.error(`❌ アップロード失敗: ${uploadResult.error}`);
   118→      updateManifestStatus(
   119→        tempFileId,
   120→        'failed',
   121→        uploadResult.error || 'アップロードに失敗しました'
   122→      );
   123→      return;
   124→    }
   125→
   126→    // 成功時: ステータスを更新し、実際のfile_idに置き換え
   127→    updateManifestStatus(tempFileId, 'completed', undefined, uploadResult.file_id);
   128→    console.log(`✅ バックグラウンドアップロード完了: ${uploadResult.file_id}`);
   129→  } catch (error) {
   130→    console.error('❌ バックグラウンドアップロードエラー:', error);
   131→    updateManifestStatus(
   132→      tempFileId,
   133→      'failed',
   134→      error instanceof Error ? error.message : '予期しないエラーが発生しました'
   135→    );
   136→  }
   137→}
   138→
   139→/**
   140→ * ファイルアップロードAPI
   141→ * POST /api/admin/upload
   142→ *
   143→ * 非同期処理: 即座にレスポンスを返し、バックグラウンドでアップロード
   144→ */
   145→export async function POST(request: NextRequest) {
   146→  try {
   147→    // FormDataからファイルとメタデータを取得
   148→    const formData = await request.formData();
   149→    const file = formData.get('file') as File | null;
   150→    const category = (formData.get('category') as string) || undefined;
   151→    const locale = (formData.get('locale') as string) || 'ja';
   152→    const sourceType = (formData.get('source_type') as 'qa' | 'web') || 'qa';
   153→
   154→    // バリデーション
   155→    if (!file) {
   156→      return NextResponse.json<AdminApiResponse>(
   157→        { success: false, error: 'ファイルが選択されていません' },
   158→        { status: 400 }
   159→      );
   160→    }
   161→
   162→    // ファイルサイズチェック
   163→    if (file.size > MAX_FILE_SIZE) {
   164→      return NextResponse.json<AdminApiResponse>(
   165→        { success: false, error: 'ファイルサイズが大きすぎます（上限: 4.5MB）' },
   166→        { status: 400 }
   167→      );
   168→    }
   169→
   170→    // ファイル拡張子チェック
   171→    const ext = path.extname(file.name).toLowerCase();
   172→    if (!ALLOWED_EXTENSIONS.includes(ext)) {
   173→      return NextResponse.json<AdminApiResponse>(
   174→        {
   175→          success: false,
   176→          error: `対応していないファイル形式です。対応形式: ${ALLOWED_EXTENSIONS.join(', ')}`,
   177→        },
   178→        { status: 400 }
   179→      );
   180→    }
   181→
   182→    // Gemini API キーチェック
   183→    const apiKey = process.env.GEMINI_API_KEY;
   184→    if (!apiKey) {
   185→      console.error('❌ GEMINI_API_KEY環境変数が設定されていません');
   186→      return NextResponse.json<AdminApiResponse>(
   187→        { success: false, error: 'サーバー設定エラー' },
   188→        { status: 500 }
   189→      );
   190→    }
   191→
   192→    // ファイル内容を読み込む
   193→    const arrayBuffer = await file.arrayBuffer();
   194→    let content: string;
   195→
   196→    // Excelファイルの場合は変換処理
   197→    if (['.xlsx', '.xls'].includes(ext)) {
   198→      const xlsx = await import('xlsx');
   199→      const workbook = xlsx.read(arrayBuffer);
   200→      content = '';
   201→
   202→      // 全シートをテキストに変換
   203→      for (const sheetName of workbook.SheetNames) {
   204→        const sheet = workbook.Sheets[sheetName];
   205→        content += `## ${sheetName}\n\n`;
   206→        content += xlsx.utils.sheet_to_csv(sheet);
   207→        content += '\n\n';
   208→      }
   209→    } else {
   210→      // テキストファイルとして読み込み
   211→      const decoder = new TextDecoder('utf-8');
   212→      content = decoder.decode(arrayBuffer);
   213→    }
   214→
   215→    // display_nameを生成（プレフィックスなし、元のファイル名をそのまま使用）
   216→    const displayName = file.name;
   217→    const finalCategory = category || path.basename(file.name, ext);
   218→
   219→    // 一時的なfile_idを生成（アップロード中の識別用）
   220→    const tempFileId = `uploading-${Date.now()}`;
   221→
   222→    // Vercel環境では同期的にアップロード（バックグラウンド処理は関数終了で中断されるため）
   223→    if (isVercel) {
   224→      console.log(`[Vercel] 同期アップロード開始: ${displayName}`);
   225→
   226→      // Store Documents APIで同名ドキュメントを検索・削除（重複防止）
   227→      const fileSearchStoreName = process.env.FILE_SEARCH_STORE_NAME;
   228→      if (fileSearchStoreName) {
   229→        console.log(`🔍 同名ドキュメントを検索中: ${displayName}`);
   230→        const deletedCount = await deleteDocumentsByDisplayName(
   231→          apiKey,
   232→          fileSearchStoreName,
   233→          displayName
   234→        );
   235→        if (deletedCount > 0) {
   236→          console.log(`🗑️ 既存ドキュメントを削除しました: ${deletedCount}件`);
   237→        }
   238→      }
   239→
   240→      const uploadResult = await uploadToFileStore(apiKey, content, {
   241→        display_name: displayName,
   242→        source_type: sourceType,
   243→        locale: locale,
   244→        category: finalCategory,
   245→      });
   246→
   247→      if (!uploadResult.success) {
   248→        console.error(`❌ アップロード失敗: ${uploadResult.error}`);
   249→        return NextResponse.json<AdminApiResponse>(
   250→          { success: false, error: uploadResult.error || 'アップロードに失敗しました' },
   251→          { status: 500 }
   252→        );
   253→      }
   254→
   255→      console.log(`✅ アップロード完了: ${uploadResult.file_id}`);
   256→      return NextResponse.json<AdminApiResponse>({
   257→        success: true,
   258→        data: {
   259→          file_id: uploadResult.file_id,
   260→          display_name: displayName,
   261→          category: finalCategory,
   262→          locale: locale,
   263→          source_type: sourceType,
   264→          status: 'completed',
   265→        },
   266→      });
   267→    }
   268→
   269→    // ローカル環境: Manifest に "uploading" ステータスで登録してバックグラウンド処理
   270→    const manifestFile: ManifestFile = {
   271→      file_id: tempFileId,
   272→      display_name: displayName,
   273→      source_type: sourceType,
   274→      uploaded_at: new Date().toISOString(),
   275→      locale: locale,
   276→      category: finalCategory,
   277→    };
   278→
   279→    try {
   280→      const manifestPath = getManifestPath();
   281→      let manifest: any;
   282→      if (fs.existsSync(manifestPath)) {
   283→        manifest = JSON.parse(fs.readFileSync(manifestPath, 'utf-8'));
   284→      } else {
   285→        manifest = { version: '3.0.0', updated_at: '', files: [] };
   286→      }
   287→
   288→      manifest.files.push({
   289→        ...manifestFile,
   290→        status: 'uploading',
   291→      });
   292→      manifest.updated_at = new Date().toISOString();
   293→      fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
   294→    } catch (error) {
   295→      console.error('Manifest write failed:', error);
   296→    }
   297→
   298→    // バックグラウンドでアップロード処理を開始（awaitしない）
   299→    processUploadInBackground(
