    58→/**
    59→ * File Search Storeからドキュメント一覧を取得
    60→ */
    61→async function fetchDocumentsFromStore(apiKey: string, storeName: string): Promise<any[]> {
    62→  const allDocs: any[] = [];
    63→  let pageToken: string | undefined;
    64→
    65→  // storeNameがフルパスでない場合は追加
    66→  const fullStoreName = storeName.startsWith('fileSearchStores/')
    67→    ? storeName
    68→    : `fileSearchStores/${storeName}`;
    69→
    70→  do {
    71→    const url = new URL(
    72→      `https://generativelanguage.googleapis.com/v1beta/${fullStoreName}/documents`
    73→    );
    74→    url.searchParams.set('pageSize', '20');
    75→    if (pageToken) {
    76→      url.searchParams.set('pageToken', pageToken);
    77→    }
    78→
    79→    const response = await fetch(url.toString(), {
    80→      method: 'GET',
    81→      headers: {
    82→        'x-goog-api-key': apiKey,
    83→      },
    84→      // キャッシュを無効化して常に最新データを取得
    85→      cache: 'no-store',
    86→    });
    87→
    88→    if (!response.ok) {
    89→      const error = await response.json();
    90→      console.error('[Admin Files API] API error:', error);
    91→      throw new Error(`API error: ${error.error?.message || 'Unknown error'}`);
    92→    }
    93→
    94→    const data = await response.json();
    95→
    96→    if (data.documents) {
    97→      allDocs.push(...data.documents);
    98→    }
    99→    pageToken = data.nextPageToken;
   100→  } while (pageToken);
   101→
   102→  return allDocs;
   103→}
   104→
   105→/**
   106→ * ドキュメントからメタデータを抽出
   107→ */
   108→function getMetadata(doc: any, key: string): string | undefined {
   109→  return doc.customMetadata?.find((m: any) => m.key === key)?.stringValue;
   110→}
   111→
   112→/**
   113→ * ファイル一覧取得API
   114→ * GET /api/admin/files
   115→ *
   116→ * 常にFile Search Store APIから直接データを取得（自動同期）
   117→ * source_type: 'qa' のファイルのみを返す
   118→ */
   119→export async function GET(): Promise<NextResponse<AdminApiResponse<FilesResponseData>>> {
   120→  try {
   121→    const apiKey = process.env.GEMINI_API_KEY;
   122→    if (!apiKey) {
   123→      return NextResponse.json(
   124→        { success: false, error: 'GEMINI_API_KEY not configured' },
   125→        { status: 500 }
   126→      );
   127→    }
   128→
   129→    const storeName = process.env.FILE_SEARCH_STORE_NAME;
   130→    if (!storeName) {
   131→      return NextResponse.json(
   132→        { success: false, error: 'FILE_SEARCH_STORE_NAME not configured' },
   133→        { status: 500 }
   134→      );
   135→    }
   136→
   137→    console.log(`[Admin Files API] Fetching from File Search Store: ${storeName}`);
   138→
   139→    // File Search Store APIからドキュメント一覧を取得
   140→    const documents = await fetchDocumentsFromStore(apiKey, storeName);
   141→    console.log(`[Admin Files API] Fetched ${documents.length} documents`);
   142→
   143→    // ドキュメントをファイル情報に変換し、QAファイルのみをフィルタ
   144→    // 注: STATE_ACTIVE以外のファイル（処理中など）も表示する
   145→    const qaFiles = documents
   146→      .filter(doc => {
   147→        const sourceType = getMetadata(doc, 'source_type');
   148→        return sourceType === 'qa';
   149→      })
   150→      .map(doc => {
   151→        // ドキュメントの状態をステータスにマッピング
   152→        let status: 'completed' | 'uploading' | 'failed' = 'uploading';
   153→        if (doc.state === 'STATE_ACTIVE') {
   154→          status = 'completed';
   155→        } else if (doc.state === 'STATE_FAILED') {
   156→          status = 'failed';
   157→        }
   158→
   159→        return {
   160→          file_id: doc.name,
   161→          display_name: doc.displayName || doc.name,
   162→          source_type: 'qa' as const,
   163→          uploaded_at: doc.createTime,
   164→          locale: getMetadata(doc, 'locale') || 'ja',
   165→          category: getMetadata(doc, 'category') || '',
   166→          state: doc.state,
   167→          status,
   168→          size_bytes: doc.sizeBytes,
   169→        };
   170→      });
   171→
   172→    console.log(`[Admin Files API] QA files: ${qaFiles.length}`);
   173→
   174→    // manifestからアップロード中のファイルを取得して追加（ローカル環境のみ）
   175→    const uploadingFiles = getUploadingFilesFromManifest();
   176→    if (uploadingFiles.length > 0) {
   177→      console.log(`[Admin Files API] Uploading files from manifest: ${uploadingFiles.length}`);
   178→    }
   179→
   180→    // File Search Storeのファイルとアップロード中のファイルを結合
   181→    // 重複を避けるため、同じdisplay_nameのファイルは除外
   182→    const storeDisplayNames = new Set(qaFiles.map(f => f.display_name));
   183→    const uniqueUploadingFiles = uploadingFiles.filter(f => !storeDisplayNames.has(f.display_name));
   184→    const allFiles = [...qaFiles, ...uniqueUploadingFiles];
   185→
   186→    return NextResponse.json({
   187→      success: true,
   188→      data: {
   189→        store_name: storeName,
   190→        files: allFiles,
   191→      },
   192→    });
   193→  } catch (error) {
   194→    console.error('[Admin Files API] Error:', error);
   195→    return NextResponse.json(
   196→      {
   197→        success: false,
   198→        error: error instanceof Error ? error.message : 'Failed to fetch file list',
   199→      },
   200→      { status: 500 }
   201→    );
   202→  }
   203→}
