    62→function loadUrlMapping(): Map<string, string> {
    63→  const mapping = new Map<string, string>();
    64→
    65→  try {
    66→    const storeName = process.env.FILE_SEARCH_STORE_NAME || '';
    67→    const isStaging = storeName.includes('staging');
    68→    const fileName = isStaging ? 'crawl-urls-staging.csv' : 'crawl-urls.csv';
    69→    const csvPath = path.join(process.cwd(), 'data', fileName);
    70→
    71→    if (!fsSync.existsSync(csvPath)) {
    72→      // ステージング用がなければ通常版を試す
    73→      const fallbackPath = path.join(process.cwd(), 'data', 'crawl-urls.csv');
    74→      if (!fsSync.existsSync(fallbackPath)) {
    75→        return mapping;
    76→      }
    77→      const content = fsSync.readFileSync(fallbackPath, 'utf-8');
    78→      parseUrlCsv(content, mapping);
    79→    } else {
    80→      const content = fsSync.readFileSync(csvPath, 'utf-8');
    81→      parseUrlCsv(content, mapping);
    82→    }
    83→  } catch (error) {
    84→    console.error('[Admin URLs API] Failed to load URL mapping:', error);
    85→  }
    86→
    87→  return mapping;
    88→}
    89→
    90→function parseUrlCsv(content: string, mapping: Map<string, string>): void {
    91→  const lines = content.split('\n').filter(line => line.trim());
    92→  // Skip header
    93→  for (let i = 1; i < lines.length; i++) {
    94→    const parts = lines[i].split(',').map(p => p.trim());
    95→    if (parts.length >= 2) {
    96→      const url = parts[0];
    97→      const category = parts[1];
    98→      // カテゴリーからURLへのマッピング（大文字小文字無視）
    99→      mapping.set(category.toLowerCase(), url);
   100→    }

