     1→/**
     2→ * Structured Logger
     3→ * 構造化ログ出力ユーティリティ
     4→ *
     5→ * Pino-based structured logging for server-side operations.
     6→ * Provides consistent log formatting with timestamp, level, request ID, and context.
     7→ *
     8→ * Features:
     9→ * - JSON structured output in production
    10→ * - Pretty print in development
    11→ * - Request ID tracking for request correlation
    12→ * - Context-aware child loggers
    13→ * - Log levels: debug, info, warn, error
    14→ */
    15→
    16→import pino from 'pino';
    17→
    18→/**
    19→ * Logger configuration based on environment
    20→ */
    21→const isDevelopment = process.env.NODE_ENV !== 'production';
    22→
    23→/**
    24→ * Service metadata for log context
    25→ */
    26→const serviceContext = {
    27→  service: 'wmg2027-chatbot',
    28→  version: process.env.npm_package_version || '0.1.0',
    29→  environment: process.env.NODE_ENV || 'development',
    30→};
    31→
    32→/**
    33→ * Create pino logger instance with structured output
    34→ */
    35→export const logger = pino({
    36→  level: process.env.LOG_LEVEL || (isDevelopment ? 'debug' : 'info'),
    37→  formatters: {
    38→    level: label => {
    39→      return { level: label.toUpperCase() };
    40→    },
    41→    bindings: () => {
    42→      // Include service context in all log messages
    43→      return serviceContext;
    44→    },
    45→  },
    46→  timestamp: pino.stdTimeFunctions.isoTime,
    47→  // Add request ID mixin when available
    48→  mixin: () => {
    49→    return {};
    50→  },
    51→  // Pretty print in development for better readability
    52→  ...(isDevelopment && {
    53→    transport: {
    54→      target: 'pino-pretty',
    55→      options: {
    56→        colorize: true,
    57→        translateTime: 'SYS:standard',
    58→        ignore: 'pid,hostname',
    59→      },
    60→    },
    61→  }),
    62→});
    63→
    64→/**
    65→ * Generate a unique request ID
    66→ */
    67→export function generateRequestId(): string {
    68→  return `req_${Date.now().toString(36)}_${Math.random().toString(36).substring(2, 11)}`;
    69→}
    70→
    71→/**
    72→ * Request context interface
    73→ */
    74→export interface RequestContext {
    75→  requestId: string;
    76→  method?: string;
    77→  path?: string;
    78→  userAgent?: string;
    79→  ip?: string;
    80→  [key: string]: unknown;
    81→}
    82→
    83→/**
    84→ * Create a child logger with specific context
    85→ * @param context - Context object to be included in all log messages
    86→ * @returns Child logger instance
    87→ */
    88→export function createLogger(context: Record<string, unknown>) {
    89→  return logger.child(context);
    90→}
    91→
    92→/**
    93→ * Create a request-scoped logger with request ID and metadata
    94→ * @param requestId - Unique request identifier
    95→ * @param context - Additional context for the request
    96→ * @returns Child logger with request context
    97→ */
    98→export function createRequestLogger(requestId: string, context?: Partial<RequestContext>) {
    99→  return logger.child({
   100→    requestId,
   101→    ...context,
   102→  });
   103→}
   104→
   105→/**
   106→ * Get or create a request ID from headers
   107→ * Uses x-request-id header if present, otherwise generates a new one
   108→ * Note: This function uses dynamic import to avoid bundling issues
   109→ */
   110→export async function getRequestId(): Promise<string> {
   111→  try {
   112→    const { headers } = await import('next/headers');
   113→    const headersList = await headers();
   114→    const existingId = headersList.get('x-request-id');
   115→    return existingId || generateRequestId();
   116→  } catch {
   117→    // headers() may fail outside of request context
   118→    return generateRequestId();
   119→  }
   120→}
   121→
   122→/**
   123→ * Create a logger for the current request context
   124→ * Automatically extracts request ID and common headers
   125→ * Note: This function uses dynamic import to avoid bundling issues
   126→ */
   127→export async function createRequestContextLogger(): Promise<pino.Logger> {
   128→  try {
   129→    const { headers } = await import('next/headers');
   130→    const headersList = await headers();
   131→    const requestId = headersList.get('x-request-id') || generateRequestId();
   132→    const userAgent = headersList.get('user-agent') || undefined;
   133→    const forwardedFor = headersList.get('x-forwarded-for');
   134→    const realIp = headersList.get('x-real-ip');
   135→    const ip = forwardedFor?.split(',')[0]?.trim() || realIp || undefined;
   136→
   137→    return logger.child({
   138→      requestId,
   139→      userAgent,
   140→      ip,
   141→    });
   142→  } catch {
   143→    // Fall back to base logger outside of request context
   144→    return logger.child({ requestId: generateRequestId() });
   145→  }
   146→}
   147→
   148→/**
   149→ * Log levels enum for type-safe level selection
   150→ */
   151→export enum LogLevel {
   152→  DEBUG = 'debug',
   153→  INFO = 'info',
   154→  WARN = 'warn',
   155→  ERROR = 'error',
   156→}
   157→
   158→/**
   159→ * Structured log entry interface
   160→ */
   161→export interface LogEntry {
   162→  level: LogLevel;
   163→  message: string;
   164→  timestamp?: string;
   165→  requestId?: string;
   166→  context?: Record<string, unknown>;
   167→  error?: {
   168→    name: string;
   169→    message: string;
   170→    stack?: string;
   171→  };
   172→}
   173→
   174→/**
   175→ * Format an error object for logging
   176→ */
   177→export function formatError(error: unknown): LogEntry['error'] {
   178→  if (error instanceof Error) {
   179→    return {
   180→      name: error.name,
   181→      message: error.message,
   182→      stack: error.stack,
   183→    };
   184→  }
   185→  return {
   186→    name: 'UnknownError',
   187→    message: String(error),
   188→  };
   189→}
   190→
   191→/**
   192→ * Client-side logger for browser environments
   193→ * Falls back to console.* methods with structured output
   194→ */
   195→export const clientLogger = {
   196→  info: (message: string, data?: Record<string, unknown>) => {
   197→    if (typeof window !== 'undefined') {
   198→      const logEntry = {
   199→        level: 'INFO',
   200→        message,
   201→        timestamp: new Date().toISOString(),
   202→        ...data,
   203→      };
   204→      if (isDevelopment) {
   205→        console.log(`[INFO] ${message}`, data || '');
   206→      } else {
   207→        console.log(JSON.stringify(logEntry));
   208→      }
   209→    }
   210→  },
   211→  warn: (message: string, data?: Record<string, unknown>) => {
   212→    if (typeof window !== 'undefined') {
   213→      const logEntry = {
   214→        level: 'WARN',
   215→        message,
   216→        timestamp: new Date().toISOString(),
   217→        ...data,
   218→      };
   219→      if (isDevelopment) {
   220→        console.warn(`[WARN] ${message}`, data || '');
   221→      } else {
   222→        console.warn(JSON.stringify(logEntry));
   223→      }
   224→    }
   225→  },
   226→  error: (message: string, error?: unknown) => {
   227→    if (typeof window !== 'undefined') {
   228→      const logEntry = {
   229→        level: 'ERROR',
   230→        message,
   231→        timestamp: new Date().toISOString(),
   232→        error: error ? formatError(error) : undefined,
   233→      };
   234→      if (isDevelopment) {
   235→        console.error(`[ERROR] ${message}`, error || '');
   236→      } else {
   237→        console.error(JSON.stringify(logEntry));
   238→      }
   239→    }
   240→  },
   241→  debug: (message: string, data?: Record<string, unknown>) => {
   242→    if (typeof window !== 'undefined' && isDevelopment) {
   243→      console.debug(`[DEBUG] ${message}`, data || '');
   244→    }
   245→  },
   246→};
